output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?artist ?albums_sold WHERE {
  VALUES ?artist {
    wd:Q3511459 wd:Q223538
  }
  ?artist wdt:P1615 ?albums_sold
}
ORDER BY DESC(?albums_sold)
LIMIT 1

